"""Batch-size-invariant eval aggregation: per-position correct/denom counts are
summed over the whole eval set (all batches, all DP ranks) BEFORE any ratio or
geometric sum. The evaluator's own collective schedule is decided globally, so
empty or scalar-only shards issue the same reductions as their peers; when
``forward_fn`` is itself collective (FSDP), every rank must additionally
iterate the same number of eval batches."""

from __future__ import annotations

from typing import Any, Callable, Dict, Iterable, List, Optional

import torch
import torch.distributed as dist

from specforge.runtime.contracts import TrainBatch
from specforge.training.strategies.base import StepOutput


class Evaluator:
    """Aggregate a full eval pass into ``eval/*`` metrics.

    ``eval/avg_acc``: for per-position (TTT) strategies, position-0 accuracy
    from eval-set-wide correct/denom counts; for scalar strategies
    (DFlash/Domino), the ``accuracy_denom``-weighted mean of batch accuracy.
    """

    def run(
        self,
        forward_fn: Callable[[TrainBatch], StepOutput],
        batches: Optional[Iterable[TrainBatch]],
    ) -> Dict[str, Any]:
        """Run the pass; returns ``{}`` if zero batches were processed globally.

        Scalar accuracy is weighted by ``metrics['accuracy_denom']`` when present,
        else by the loss-token count — only approximately batch-size invariant
        when the accuracy counts a different token set than the loss. In a mixed
        pass, scalar batches feed avg_loss only; their accuracy is not merged.
        """
        # pp rows: [correct, denom, acceptance_rate*w, ploss*w] per TTT
        # position, float64 so counts stay exact past 2**24.
        pp = None
        # [loss*w, w, scalar_acc*denom, scalar_denom, n_batches, ar_w, pl_w]
        sums = None

        with torch.no_grad():
            for batch in batches if batches is not None else ():
                out = forward_fn(batch)
                m = out.metrics
                # .mean() normalizes a shape-[1] loss to the 0-dim slot.
                loss = (
                    out.loss.detach().double().mean()
                    if isinstance(out.loss, torch.Tensor)
                    else torch.tensor(float(out.loss), dtype=torch.float64)
                )
                if sums is None:
                    sums = torch.zeros(7, dtype=torch.float64, device=loss.device)
                tokens = self._token_count(batch, m, device=sums.device)
                sums[0] += loss.to(sums.device) * tokens
                sums[1] += tokens
                sums[4] += 1.0

                if "acc_corrects" in m and "acc_denoms" in m:
                    correct = self._stack(m["acc_corrects"])
                    denom = self._stack(m["acc_denoms"])
                    if pp is None:
                        pp = torch.zeros(
                            4,
                            correct.numel(),
                            dtype=torch.float64,
                            device=correct.device,
                        )
                    pp[0] += correct
                    pp[1] += denom
                    w = tokens.to(pp.device)
                    if "acceptance_rates" in m:
                        pp[2] += self._stack(m["acceptance_rates"]) * w
                        sums[5] += tokens
                    if "plosses" in m:
                        pp[3] += self._stack(m["plosses"]) * w
                        sums[6] += tokens
                elif "accuracy" in m:
                    acc = m["accuracy"]
                    acc = (
                        acc.detach().double().mean().to(sums.device)
                        if isinstance(acc, torch.Tensor)
                        else torch.tensor(
                            float(acc), dtype=torch.float64, device=sums.device
                        )
                    )
                    denom = m.get("accuracy_denom")
                    w = (
                        torch.as_tensor(denom).detach().double().sum().to(sums.device)
                        if denom is not None
                        else tokens
                    )
                    sums[2] += acc * w
                    sums[3] += w

        # Fixed global schedule, identical on every rank: (1) SUM the scalar
        # sums, (2) MAX the per-position length — a global decision, so an
        # empty shard still participates — (3) SUM one padded count buffer iff
        # any rank has per-position data.
        world_size = dist.get_world_size() if dist.is_initialized() else 1
        if world_size > 1:
            device = self._comm_device()
            sums = (
                sums if sums is not None else torch.zeros(7, dtype=torch.float64)
            ).to(device)
            dist.all_reduce(sums, op=dist.ReduceOp.SUM)
            local_len = pp.size(1) if pp is not None else 0
            pp_len = torch.tensor([local_len], dtype=torch.int64, device=device)
            dist.all_reduce(pp_len, op=dist.ReduceOp.MAX)
            global_len = int(pp_len.item())
            if global_len > 0:
                buf = torch.zeros(4, global_len, dtype=torch.float64, device=device)
                if pp is not None:
                    buf[:, : pp.size(1)] = pp.to(device)
                dist.all_reduce(buf, op=dist.ReduceOp.SUM)
                pp = buf

        if sums is None or sums[4].item() == 0.0:
            # Zero batches globally: report nothing — fabricated zero metrics
            # would poison best-checkpoint tracking.
            return {}

        loss_x_w, loss_w, acc_sum, acc_w, _n, ar_w, pl_w = sums.tolist()
        avg_loss = loss_x_w / max(loss_w, 1.0)

        if pp is not None:
            pp = pp.cpu()
            per_position_acc = (pp[0] / pp[1].clamp_min(1.0)).tolist()
            metrics = {
                "eval/avg_loss": avg_loss,
                "eval/avg_acc": float(per_position_acc[0]),
                "eval/per_position_acc": per_position_acc,
                "eval/simulated_acc_len": self._simulated_acc_len(per_position_acc),
            }
            if ar_w > 0:
                for i, v in enumerate((pp[2] / ar_w).tolist()):
                    metrics[f"eval/acceptance_rate_{i}"] = v
            if pl_w > 0:
                for i, v in enumerate((pp[3] / pl_w).tolist()):
                    metrics[f"eval/ploss_{i}"] = v
            return metrics

        avg_acc = acc_sum / acc_w if acc_w else 0.0
        return {
            "eval/avg_loss": avg_loss,
            "eval/avg_acc": avg_acc,
            "eval/simulated_acc_len": avg_acc,
        }

    @staticmethod
    def _stack(values: Iterable[Any]) -> torch.Tensor:
        return torch.stack([torch.as_tensor(v).detach().double() for v in values])

    @staticmethod
    def _comm_device() -> torch.device:
        """Return the bound device required by the active collective backend."""
        backend = str(dist.get_backend()).lower()
        if "nccl" in backend:
            return torch.device("cuda", torch.cuda.current_device())
        if "hccl" in backend:
            from specforge.utils import get_local_device

            device = get_local_device()
            if device.type != "npu":
                raise RuntimeError(
                    "HCCL evaluation requires SPECFORGE_DEVICE=npu and a bound "
                    f"NPU device, got {device}"
                )
            return device
        return torch.device("cpu")

    @staticmethod
    def _simulated_acc_len(per_position_acc: List[float]) -> float:
        """E[accepted tokens] = a0 + a0*a1 + ... over the eval-set-wide
        per-position accuracy (length = ttt_length)."""
        cumulative, total = 1.0, 0.0
        for acc in per_position_acc:
            cumulative *= acc
            total += cumulative
        return total

    @staticmethod
    def _token_count(
        batch: TrainBatch, metrics: Dict[str, Any], device
    ) -> torch.Tensor:
        """This batch's token weight as a 0-dim float64 tensor (no host sync):
        the strategy's loss denoms, else the loss mask, else 1."""
        denoms = metrics.get("metric_loss_denoms")
        if denoms:
            return (
                torch.stack([torch.as_tensor(d).detach().float() for d in denoms])
                .sum()
                .double()
                .to(device)
            )
        loss_mask = batch.tensors.get("loss_mask")
        if isinstance(loss_mask, torch.Tensor):
            return loss_mask.sum().double().to(device)
        return torch.ones((), dtype=torch.float64, device=device)


__all__ = ["Evaluator"]

"""Benchmark a running SGLang server.

Request scheduling is adapted from z-lab/dflash's MIT benchmark:
https://github.com/z-lab/dflash/blob/main/dflash/benchmark.py

The runner is speculative-algorithm agnostic and consumes SGLang's optional
speculative-decoding metadata when the server returns it.
"""

from __future__ import annotations

import json
import random
import statistics
import time
from concurrent.futures import ThreadPoolExecutor, as_completed
from dataclasses import asdict, dataclass
from typing import Any, Optional

DATASETS: dict[str, dict[str, Any]] = {
    "gsm8k": {
        "load_args": ("openai/gsm8k", "main"),
        "load_kwargs": {"split": "test"},
        "format": lambda row: (
            f"{row['question']}\nPlease reason step by step, and put your final "
            "answer within \\boxed{}."
        ),
    },
    "math500": {
        "load_args": ("HuggingFaceH4/MATH-500",),
        "load_kwargs": {"split": "test"},
        "format": lambda row: (
            f"{row['problem']}\nPlease reason step by step, and put your final "
            "answer within \\boxed{}."
        ),
    },
    "humaneval": {
        "load_args": ("openai/openai_humaneval",),
        "load_kwargs": {"split": "test"},
        "format": lambda row: (
            "Write a solution to the following problem and make sure that it "
            f"passes the tests:\n```python\n{row['prompt']}\n```"
        ),
    },
    "mbpp": {
        "load_args": ("google-research-datasets/mbpp", "sanitized"),
        "load_kwargs": {"split": "test"},
        "format": lambda row: row["prompt"],
    },
    "mt-bench": {
        "load_args": ("HuggingFaceH4/mt_bench_prompts",),
        "load_kwargs": {"split": "train"},
        "format": lambda row: row["prompt"],
        "multi_turn": True,
    },
}


@dataclass(frozen=True)
class BenchmarkResult:
    backend: str
    dataset: str
    samples: int
    output_tokens: int
    latency_seconds: float
    throughput_tokens_per_second: float
    average_acceptance_length: Optional[float] = None
    spec_verify_count: Optional[int] = None


def _load_prompts(name: str, max_samples: Optional[int]) -> list[list[str]]:
    from datasets import load_dataset

    if max_samples is not None and max_samples <= 0:
        raise ValueError("--max-samples must be positive")
    descriptor = DATASETS[name]
    dataset = load_dataset(
        *descriptor["load_args"],
        **descriptor["load_kwargs"],
    )
    prompts: list[list[str]] = []
    for row in dataset:
        formatted = descriptor["format"](row)
        turns = list(formatted) if descriptor.get("multi_turn") else [formatted]
        prompts.append(turns)
    if not prompts:
        raise ValueError(f"dataset {name!r} did not contain any prompts")
    if max_samples is not None and len(prompts) > max_samples:
        random.Random(42).shuffle(prompts)
        prompts = prompts[:max_samples]
    return prompts


def _apply_chat_template(tokenizer, messages, enable_thinking: bool) -> str:
    kwargs = {
        "tokenize": False,
        "add_generation_prompt": True,
        "enable_thinking": enable_thinking,
    }
    try:
        return tokenizer.apply_chat_template(messages, **kwargs)
    except TypeError:
        kwargs.pop("enable_thinking")
        return tokenizer.apply_chat_template(messages, **kwargs)


def _send_sglang(args, prompt: str) -> dict[str, Any]:
    import requests

    response = requests.post(
        args.base_url.rstrip("/") + "/generate",
        json={
            "text": prompt,
            "sampling_params": {
                "temperature": args.temperature,
                "top_p": args.top_p,
                "top_k": args.top_k,
                "max_new_tokens": args.max_new_tokens,
            },
        },
        timeout=args.timeout_seconds,
    )
    response.raise_for_status()
    payload = response.json()
    return payload[0] if isinstance(payload, list) else payload


def _run_sglang(args) -> BenchmarkResult:
    import requests
    from transformers import AutoTokenizer

    if args.concurrency <= 0:
        raise ValueError("--concurrency must be positive")
    if args.num_prompts <= 0:
        raise ValueError("--num-prompts must be positive")
    tokenizer = AutoTokenizer.from_pretrained(
        args.model,
        trust_remote_code=args.trust_remote_code,
    )
    dataset = _load_prompts(args.dataset, args.max_samples)
    prompt_count = args.num_prompts
    warmup_count = args.concurrency
    prompts = [
        _apply_chat_template(
            tokenizer,
            [{"role": "user", "content": dataset[index % len(dataset)][0]}],
            args.enable_thinking,
        )
        for index in range(prompt_count + warmup_count)
    ]

    try:
        requests.get(
            args.base_url.rstrip("/") + "/flush_cache",
            timeout=min(args.timeout_seconds, 60),
        ).raise_for_status()
    except requests.RequestException:
        print("Warning: /flush_cache failed. Continuing.")

    with ThreadPoolExecutor(max_workers=warmup_count) as executor:
        list(
            executor.map(
                lambda prompt: _send_sglang(args, prompt), prompts[:warmup_count]
            )
        )
    prompts = prompts[warmup_count:]

    total_tokens = 0
    verify_count = 0
    acceptance_lengths: list[float] = []
    start = time.perf_counter()
    with ThreadPoolExecutor(max_workers=args.concurrency) as executor:
        futures = [executor.submit(_send_sglang, args, prompt) for prompt in prompts]
        for future in as_completed(futures):
            output = future.result()
            metadata = output.get("meta_info", {}) or {}
            total_tokens += int(metadata.get("completion_tokens", 0))
            verify_count += int(metadata.get("spec_verify_ct", 0))
            if metadata.get("spec_accept_length") is not None:
                try:
                    acceptance_lengths.append(float(metadata["spec_accept_length"]))
                except (TypeError, ValueError):
                    pass
    elapsed = time.perf_counter() - start
    return BenchmarkResult(
        backend="sglang",
        dataset=args.dataset,
        samples=prompt_count,
        output_tokens=total_tokens,
        latency_seconds=elapsed,
        throughput_tokens_per_second=total_tokens / max(elapsed, 1e-12),
        average_acceptance_length=(
            statistics.fmean(acceptance_lengths) if acceptance_lengths else None
        ),
        spec_verify_count=verify_count or None,
    )


def _print_result(result: BenchmarkResult) -> None:
    print(f"Backend: {result.backend}")
    print(f"Dataset: {result.dataset} ({result.samples} completed prompts/turns)")
    print(f"Output throughput: {result.throughput_tokens_per_second:.2f} tok/s")
    if result.average_acceptance_length is not None:
        print(f"Average acceptance length: {result.average_acceptance_length:.3f}")
    if result.spec_verify_count is not None:
        print(f"Speculative verify count: {result.spec_verify_count}")


def run(args) -> int:
    random.seed(42)
    result = _run_sglang(args)
    _print_result(result)
    if args.output_json:
        with open(args.output_json, "w", encoding="utf-8") as output_file:
            json.dump(asdict(result), output_file, indent=2, sort_keys=True)
            output_file.write("\n")
    return 0


__all__ = ["BenchmarkResult", "DATASETS", "run"]

class CheckpointManager:
    def __init__(
        self,
        output_dir: str,
        run_id: str,
        *,
        max_checkpoints: int = 0,
        best_metric: str = "eval/simulated_acc_len",
        best_min_delta: float = 0.0,
    ) -> None:
        self.output_dir = output_dir
        self.run_id = run_id
        self.max_checkpoints = max_checkpoints
        self.best_metric = best_metric
        self.best_min_delta = best_min_delta
        self.best_score: Optional[float] = None
        self.best_step: Optional[int] = None
        self._load_best_meta()

    # -- layout ------------------------------------------------------------
    def checkpoint_dir(self, step: int) -> str:
        return os.path.join(self.output_dir, f"{self.run_id}-step{step}")

    def _state_path(self, ckpt_dir: str) -> str:
        return os.path.join(ckpt_dir, STATE_FILE)

    @staticmethod
    def _rank_file(rank: int) -> str:
        return f"training_state_rank{rank}.pt"

    @property
    def _best_meta_path(self) -> str:
        return os.path.join(self.output_dir, f"{self.run_id}.best_meta.json")

    # -- save --------------------------------------------------------------
    def save(
        self,
        state: Optional[Dict[str, Any]],
        step: int,
        *,
        rank_state: Optional[Dict[str, Any]] = None,
    ) -> str:
        """Write ``step``'s checkpoint, first deleting any on-disk steps >= step
        (fork/rollback semantics), then repoint ``{run_id}-latest`` and rotate.
        ``state`` is the shared payload (rank0 writes it); ``rank_state`` is
        written by every rank. Collective: any rank's failure raises on all ranks.
        """
        ckpt_dir = self.checkpoint_dir(step)
        err = ""
        try:
            if self.is_rank0():
                self._rewind(step)
        except Exception as exc:
            err = f"rewind failed: {type(exc).__name__}: {exc}"
        self._barrier()  # stale >= step dirs are gone before any rank recreates them
        if not err:
            try:
                os.makedirs(ckpt_dir, exist_ok=True)
                if rank_state is not None:
                    self._atomic_save(
                        rank_state,
                        os.path.join(ckpt_dir, self._rank_file(self._rank())),
                    )
                if self.is_rank0() and state is not None:
                    self._atomic_save(state, self._state_path(ckpt_dir))
            except Exception as exc:
                err = f"{type(exc).__name__}: {exc}"
        self._all_ok(err)
        if self.is_rank0():
            self._point(f"{self.run_id}-latest", ckpt_dir)
            self._rotate(keep_step=step)
        self._barrier()  # no rank proceeds before the checkpoint is complete
        return ckpt_dir

    def _rewind(self, step: int) -> None:

    optimizer = getattr(self.core.backend, "optimizer", None)
    get_learning_rate = getattr(optimizer, "get_learning_rate", None)
    if callable(get_learning_rate):
        log_metrics["lr"] = float(get_learning_rate())
    self.logger(log_metrics, self.global_step)
eval_metrics: Optional[Dict[str, Any]] = None
if eval_enabled and self.global_step % self.eval_interval == 0:
    eval_metrics = self.evaluate_configured()
    module.train()
    if eval_metrics:
        if self.logger:
            self.logger(eval_metrics, self.global_step)
        self.last_metrics = {**self.last_metrics, **eval_metrics}
# ``is_better`` is collective (rank0 verdict broadcast inside
# the manager); its guard is rank-identical because eval metrics
# are DP-reduced. Empty eval metrics skip best tracking.
interval_hit = bool(
    self.save_interval and self.global_step % self.save_interval == 0
)
is_best = bool(
    eval_metrics and self._checkpoint_manager().is_better(eval_metrics)
)
if interval_hit or is_best:
    self.save_checkpoint(self.global_step)
if is_best:
    self._checkpoint_manager().update_best(
        self.global_step, eval_metrics
    )
if progress is not None:
    progress.update(1)
